int ft_strcmp(char *s1, char *s2)
{
    int i = 0;
    while (s1[i] && s1[i] == s2[i])
        i++;
    return (unsigned char)s1[i] - (unsigned char)s2[i];
}

void ft_putstr(char *str)
{
    while (*str)
        ft_putchar(*str++);
    ft_putchar('\n');
}

void ft_swap(char **a, char **b)
{
    char *temp = *a;
    *a = *b;
    *b = temp;
}

