#include <stdlib.h>

int *ft_range(int min, int max)
{
    int *range;
    int i = 0;

    if (min >= max)
        return NULL;
    range = (int *)malloc(sizeof(int) * (max - min));
    if (!range)
        return NULL;
    while (min < max)
        range[i++] = min++;
    return range;
}

