#include <stdlib.h>

int ft_ultimate_range(int **range, int min, int max)
{
    int size = max - min;
    int i;

    if (min >= max)
    {
        *range = NULL;
        return 0;
    }
    *range = (int *)malloc(sizeof(int) * size);
    if (!*range)
        return -1;
    for (i = 0; i < size; i++)
        (*range)[i] = min + i;
    return size;
}

