exercises.description:
Convert an array of strings to an array of structures containing each string, its copy, and length.

**Structure:**
```c
typedef struct s_stock_str {
    int size;
    char *str;
    char *copy;
} t_stock_str;
```
**Function:**
```c
t_stock_str *ft_strs_to_tab(int ac, char **av);
```

exercises.implementation:
#include <stdlib.h>

typedef struct s_stock_str {
    int size;
    char *str;
    char *copy;
} t_stock_str;

char *ft_strdup(char *src)
{
    int i = 0;
    char *copy;
    while (src[i]) i++;
    copy = malloc(i + 1);
    if (!copy) return NULL;
    for (int j = 0; j <= i; j++)
        copy[j] = src[j];
    return copy;
}

int ft_strlen(char *str)
{
    int i = 0;
    while (str[i]) i++;
    return i;
}

t_stock_str *ft_strs_to_tab(int ac, char **av)
{
    t_stock_str *arr = malloc(sizeof(t_stock_str) * (ac + 1));
    if (!arr) return NULL;
    for (int i = 0; i < ac; i++) {
        arr[i].size = ft_strlen(av[i]);
        arr[i].str = av[i];
        arr[i].copy = ft_strdup(av[i]);
    }
    arr[ac].str = NULL;
    return arr;
}

