#include <stdlib.h>

int is_sep(char c, char *charset)
{
    for (int i = 0; charset[i]; i++)
        if (c == charset[i])
            return 1;
    return 0;
}

int count_words(char *str, char *charset)
{
    int count = 0;
    int i = 0;
    while (str[i]) {
        while (str[i] && is_sep(str[i], charset)) i++;
        if (str[i]) count++;
        while (str[i] && !is_sep(str[i], charset)) i++;
    }
    return count;
}

char *word_dup(char *start, int len)
{
    char *word = malloc(len + 1);
    for (int i = 0; i < len; i++)
        word[i] = start[i];
    word[len] = '\0';
    return word;
}

char **ft_split(char *str, char *charset)
{
    int i = 0, j = 0, k, word_len;
    char **result = malloc((count_words(str, charset) + 1) * sizeof(char *));

    while (str[i]) {
        while (str[i] && is_sep(str[i], charset)) i++;
        k = i;
        while (str[i] && !is_sep(str[i], charset)) i++;
        word_len = i - k;
        if (word_len > 0)
            result[j++] = word_dup(&str[k], word_len);
    }
    result[j] = NULL;
    return result;
}

